import{_ as a,o as e,c as s,ag as n}from"./chunks/framework.CYCRomDB.js";const r=JSON.parse('{"title":"優化 Laravel 中大型 whereIn 查詢緩慢問題","description":"Laravel Eloquent whereIn() 每個人都用過，但你曉得但 whereIn() 量大時，可能會造成查詢緩慢問題之一嗎?","frontmatter":{"title":"優化 Laravel 中大型 whereIn 查詢緩慢問題","date":"2026-03-09T00:00:00.000Z","updated":"2026-03-09T00:00:00.000Z","description":"Laravel Eloquent whereIn() 每個人都用過，但你曉得但 whereIn() 量大時，可能會造成查詢緩慢問題之一嗎?","author":"Cola","tags":[],"keywords":["php","seo"],"readingTime":"3 min read","readingMinutes":3,"permalink":"/optimising-large-wherein-queries-in-laravel","slug":"optimising-large-wherein-queries-in-laravel","issueId":19,"githubUrl":"https://github.com/cscolabear/cscolabear.github.io/issues/19"},"headers":[],"relativePath":"optimising-large-wherein-queries-in-laravel.md","filePath":"posts/optimising-large-wherein-queries-in-laravel.md","lastUpdated":null}');const i=a({name:"optimising-large-wherein-queries-in-laravel.md"},[["render",function(a,r,i,l,t,p){return e(),s("div",null,[...r[0]||(r[0]=[n('<h1 id="優化-laravel-中大型-wherein-查詢緩慢問題" tabindex="-1">優化 Laravel 中大型 whereIn 查詢緩慢問題 <a class="header-anchor" href="#優化-laravel-中大型-wherein-查詢緩慢問題">#</a></h1><img width="1376" height="768" alt="Image" src="https://github.com/user-attachments/assets/9882b981-f0f2-4dd1-a7ad-bbaced386aef"><p>Laravel Eloquent whereIn() 每個人都用過，但你曉得但 whereIn() 量大時，可能會造成查詢緩慢問題之一嗎? 他不一定是資料 index 索引的問題，可能是更底層問題喔 這邊提供一個 Laravel 資料庫查詢效能優化的手式</p><h2 id="laravel-查詢緩慢的情境" tabindex="-1">Laravel 查詢緩慢的情境 <a class="header-anchor" href="#laravel-查詢緩慢的情境">#</a></h2><p>常有的需求是使用指定的 id 取出多個使用者 (e.g. my_table.users.id)</p><p>一般透過 eloquent 可能會這樣做 (這邊先不考慮分頁問題)</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User::whereIn(&#39;id&#39;, [1,2,3,4....... x100])-&gt;get()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>而實際上 Eloquent 會轉換為 SQL statement，如下~ 可以看到 SQL Binding Parameter 的 <code>?</code></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT * FROM users WHERE id in (?, ?, ?, ?, ?, ......)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但查詢對象達到一定數量之後，會發現資料庫回應速度變慢!</p><h3 id="查詢緩慢的問題原因" tabindex="-1">查詢緩慢的問題原因 <a class="header-anchor" href="#查詢緩慢的問題原因">#</a></h3><p>這是因為 Eloquent QueryBuilder 在綁定查詢參數時造成的，他不是 Laravel 的問題而是 <a href="https://www.php.net/manual/en/ref.pdo-mysql.php" target="_blank" rel="noreferrer">PHP Data Objects (PDO)</a> 一個古老的 <a href="https://bugs.php.net/bug.php?id=53458" target="_blank" rel="noreferrer">Bug</a>，PDO 在進行參數綁定時緩慢造成的 (可以想象他要依序綁上上百萬的參數...)</p><p>在 <a href="https://github.com/laravel/framework/pull/26434" target="_blank" rel="noreferrer">Laravel. 5.7</a> 之後可以改用 <a href="https://api.laravel.com/docs/12.x/Illuminate/Database/Query/Builder.html#method_whereIntegerInRaw" target="_blank" rel="noreferrer">whereIntegerInRaw</a> 替換 <code>whereIn()</code> 就如字面上的意思 (raw) 會直接將參數置入 sql 內，省去 PDO bindings 上參數的動作</p><p>替換後的查詢語法為：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User::whereIntegerInRaw(&#39;id&#39;, [1,2,3,4....... x100])-&gt;get()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>實際的 SQL statement，如下~ 直接就能看到 RAW SQL</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT * FROM users WHERE id in (1, 2, 3, 4, 5, ......)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="實際上測試如下" tabindex="-1">實際上測試如下 <a class="header-anchor" href="#實際上測試如下">#</a></h3><p>簡單重現，使用 range(1, 50000) 執行 whereIn()，約耗時 11x ms</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$avg = [];</span></span>\n<span class="line"><span>for ($i = 0; $i &lt; 10; $i++) {</span></span>\n<span class="line"><span>    $s = now();</span></span>\n<span class="line"><span>    $c =User::query()-&gt;whereIn(&#39;id&#39;, $list)-&gt;count();</span></span>\n<span class="line"><span>    $avg[] =  $s-&gt;diffInMilliseconds(now());</span></span>\n<span class="line"><span>}</span></span>\n<span class="line"><span>$r = array_sum($avg)/count($avg);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><img width="1162" height="504" alt="Image" src="https://github.com/user-attachments/assets/680a1bab-26bb-468a-882a-5f9c2461f099"><p>改用 whereIntegerInRaw() 進行查詢，可以看見大幅降低，耗時約 4x ms</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$avg = [];</span></span>\n<span class="line"><span>for ($i = 0; $i &lt; 10; $i++) {</span></span>\n<span class="line"><span>    $s = now();</span></span>\n<span class="line"><span>    $c = User::query()-&gt;whereIntegerInRaw(&#39;id&#39;, $list)-&gt;count();</span></span>\n<span class="line"><span>    $avg[] = $s-&gt;diffInMilliseconds(now());</span></span>\n<span class="line"><span>}</span></span>\n<span class="line"><span>array_sum($avg)/count($avg);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><img width="1362" height="484" alt="Image" src="https://github.com/user-attachments/assets/71816d84-8bd2-4db0-9ac8-187ce118b875"><p><a href="https://cola.workxplay.net/wp-content/uploads/2024/07/CleanShot-2024-07-05-at-14.18.37.png" target="_blank" rel="noreferrer"><img src="https://cola.workxplay.net/wp-content/uploads/2024/07/CleanShot-2024-07-05-at-14.18.37.png" alt=""></a></p><h2 id="使用限制" tabindex="-1">使用限制 <a class="header-anchor" href="#使用限制">#</a></h2><p>當然這麼好的功能當然有些限制要注意</p><ul><li><p>參數只能是 integers</p></li><li><p>要注意 SQL injection</p></li></ul><h2 id="laravel-source-code" tabindex="-1">Laravel Source Code <a class="header-anchor" href="#laravel-source-code">#</a></h2><ul><li><strong>whereIn()</strong><a href="https://github.com/laravel/framework/blob/0ac6e5592da1a172d9685591c5f82fb1fb8995fb/src/Illuminate/Database/Query/Builder.php#L1365-L1399" target="_blank" rel="noreferrer">https://github.com/laravel/framework/blob/0ac6e5592da1a172d9685591c5f82fb1fb8995fb/src/Illuminate/Database/Query/Builder.php#L1365-L1399</a></li></ul><img width="1984" height="2284" alt="Image" src="https://github.com/user-attachments/assets/c0fd743f-8e1b-4f40-a96d-402eecc9b82b"><p>可以看到將透過 addBinding() 會將目標對象的 Key 逐一綁進 SQL Query 的語句中~</p><ul><li><strong>whereIntegerInRaw()</strong><a href="https://github.com/laravel/framework/blob/0ac6e5592da1a172d9685591c5f82fb1fb8995fb/src/Illuminate/Database/Query/Builder.php#L1447-L1464" target="_blank" rel="noreferrer">https://github.com/laravel/framework/blob/0ac6e5592da1a172d9685591c5f82fb1fb8995fb/src/Illuminate/Database/Query/Builder.php#L1447-L1464</a></li></ul><img width="2018" height="1902" alt="Image" src="https://github.com/user-attachments/assets/883b5ab8-ecca-4436-ba7d-ab69adbd5dfe"><hr><div class="github-discussion"><a href="https://github.com/cscolabear/cscolabear.github.io/issues/19" target="_blank" rel="noopener noreferrer"> 💬 在 GitHub 上討論這篇文章 </a></div>',37)])])}]]);export{r as __pageData,i as default};
